SELECT ?teamsCount WHERE {
  {
    SELECT (COUNT(DISTINCT ?team) AS ?teamsCount) WHERE {
      ?season <http://dbpedia.org/ontology/chairman> <http://dbpedia.org/resource/Patrícia_Amorim> .
      ?season <http://dbpedia.org/property/name> ?team .
      ?season a <http://dbpedia.org/ontology/SportsSeason> .
    }
  }
  UNION
