SELECT DISTINCT ?driver WHERE {
  VALUES ?race1 { <http://dbpedia.org/resource/1994_Spanish_Grand_Prix> }
  VALUES ?race2 { <http://dbpedia.org/resource/1997_Canadian_Grand_Prix> }
  VALUES ?race3 { <http://dbpedia.org/resource/1989_Portuguese_Grand_Prix> }
  VALUES ?race4 { <http://dbpedia.org/resource/1993_European_Grand_Prix> }

  {
    # Check if Michael Schumacher was the pole driver of 1994 Spanish Grand Prix
    ASK {
      ?race1 <http://dbpedia.org/property/poleDriver> <http://dbpedia.org/resource/Michael_Schumacher> .
    }
  }
  UNION
  {
    # Name the driver at pole in 1997 Canadian Grand Prix and also 1994 Spanish Grand Prix
    ?race2 <http://dbpedia.org/property/poleDriver> ?driver .
    ?race1 <http://dbpedia.org/ontology/poleDriver> ?driver .
  }
  UNION
  {
    # Which pole driver of 1989 Portuguese Grand Prix was also the first driver of 1993 European Grand Prix
    ?race3 <http://dbpedia.org/ontology/poleDriver> ?driver .
    ?race4 <http://dbpedia.org/property/firstDriver> ?driver .
  }
}

