PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?river ?question
WHERE
  { VALUES ?question { "Was Zambezi originate in the north western province of zambia?" "Name the river whose mouth country is Mozambique and source region is North-Western Province, Zambia?" "What are some rivers in Zambia which have a dam on them?" }
    BIND(if(( ?question = "Was Zambezi originate in the north western province of zambia?" ), "ask", if(( ?question = "Name the river whose mouth country is Mozambique and source region is North-Western Province, Zambia?" ), "query1", if(( ?question = "What are some rivers in Zambia which have a dam on them?" ), "query2", "none"))) AS ?queryType)
    FILTER ( ?queryType != "none" )
      { FILTER ( ?queryType = "ask" )
        BIND(<http://dbpedia.org/resource/Zambezi> AS ?river)
        FILTER EXISTS { <http://dbpedia.org/resource/Zambezi>
                                  <http://dbpedia.org/property/sourceRegion>  <http://dbpedia.org/resource/North-Western_Province,_Zambia>
                      }
      }
    UNION
      { FILTER ( ?queryType = "query1" )
        ?river  <http://dbpedia.org/property/mouthCountry>  <http://dbpedia.org/resource/Mozambique> ;
